      playStoreId: "com.zerodha.kite3",
      logoUrl: "https://play-lh.googleusercontent.com/wnNYBAH1m-XJMfduOHfEATQAhCwyKUYeHAD1Fi9-OjtxKyPKjFEmgWvbx-OX2dM65xjp=s96-rw"
    },
    {
      name: "Home Workout",
      appStoreId: "313192037",
      playStoreId: "homeworkout.homeworkouts.noequipment",
      logoUrl: "https://play-lh.googleusercontent.com/NlQFS5pgo96dzbRuwZfkBhGf3ecKSGH5lRx0DSsmELYZXRYHlXrd7YVCR7tS7-R84eEVLhZ1qBIQj1WP_RCJAQ=w480-h960-rw"
    }
  ]

};

// Pass config forward to next nodes
return [{ json: config }];

// Pull app list directly from Config node — single source of truth
const config = $('Config').first().json;
const apps = config.apps || [];

// Dynamically build lookup maps from config
const appStoreIdMap = {};
const playStoreIdMap = {};
for (const app of apps) {
  if (app.appStoreId) appStoreIdMap[String(app.appStoreId)] = app.name;
  if (app.playStoreId) playStoreIdMap[app.playStoreId] = app.name;
}

const items = $input.all();
const allReviews = [];

for (const item of items) {

  // Handle App Store — stringified JSON in item.json.data
  if (item.json?.data && typeof item.json.data === 'string') {
    try {
      const parsed = JSON.parse(item.json.data);
      const feed = parsed?.feed;
      if (feed?.entry) {
        // Extract app ID from feed self link
        const selfLink = feed.link?.find(l => l.attributes?.rel === 'self')?.attributes?.href || '';
        const idMatch = selfLink.match(/id=(\d+)/);
        const appId = idMatch ? idMatch[1] : '';
        const appName = appStoreIdMap[appId] || 'Unknown App';

        const entries = Array.isArray(feed.entry) ? feed.entry : [feed.entry];
        for (const entry of entries) {
          if (!entry['im:rating']) continue;
          allReviews.push({
            app: appName,
            store: 'App Store',
            rating: parseInt(entry['im:rating']?.label || '0'),
            title: entry.title?.label || '',
            review: entry.content?.label || '',
            author: entry.author?.name?.label || 'Anonymous',
            date: entry.updated?.label || ''
          });
        }
      }
    } catch(e) {}
  }

  // Handle Play Store — data at item.json.results.data
  const playReviews = item.json?.results?.data;
  if (Array.isArray(playReviews)) {
    for (const r of playReviews) {
      // Extract package name from Play Store URL
     const packageMatch = (r.url || '').match(/[?&]id=([^&]+)/);
      const packageName = packageMatch ? packageMatch[1] : '';
      const appName = playStoreIdMap[packageName] || 'Unknown App';

      allReviews.push({
        app: appName,
        store: 'Play Store',
        rating: r.score || 0,
        title: '',
        review: r.text || '',
        author: r.userName || 'Anonymous',
        date: r.date || ''
      });
    }
  }
}

return [{
  json: {
    totalReviews: allReviews.length,
    reviews: allReviews,
    fetchedAt: new Date().toISOString()
  }
}];

