const data = $input.first().json;
const config = $('Config').first().json;
const reviews = data.reviews || [];

// Group reviews by app
const grouped = {};
for (const r of reviews) {
  const key = r.app;
  if (!grouped[key]) grouped[key] = [];
  grouped[key].push(r);
}

// Build app metadata map from config
const appMeta = {};
for (const app of config.apps) {
  appMeta[app.name] = {
    logoUrl: app.logoUrl || '',
    appStoreId: app.appStoreId || '',
    playStoreId: app.playStoreId || ''
  };
}

// Build review text per app with metadata
let reviewText = '';
const reportMetadata = {};

for (const [appName, appReviews] of Object.entries(grouped)) {
  const avgRating = (appReviews.reduce((s, r) => s + r.rating, 0) / appReviews.length).toFixed(1);

  // Count by store
  const storeBreakdown = {};
  for (const r of appReviews) {
    storeBreakdown[r.store] = (storeBreakdown[r.store] || 0) + 1;
  }

  // Human readable store summary
  const storeSummaryParts = Object.entries(storeBreakdown).map(([store, count]) => `${count} from ${store}`);
  const storeSummary = storeSummaryParts.join(' and ');
  const storesCovered = Object.keys(storeBreakdown);
  const storesCoveredLabel = storesCovered.length === 2
    ? 'App Store and Play Store'
    : `${storesCovered[0]} only`;

  // Date range
  const dates = appReviews.map(r => new Date(r.date)).filter(d => !isNaN(d));
  const newestDate = dates.length ? new Date(Math.max(...dates)).toDateString() : 'N/A';
  const oldestDate = dates.length ? new Date(Math.min(...dates)).toDateString() : 'N/A';

  reportMetadata[appName] = {
    totalReviews: appReviews.length,
    storeSummary,
    storesCoveredLabel,
    dateRange: `${oldestDate} to ${newestDate}`,
    avgRating
  };

  reviewText += `\n\n=== ${appName} | ${appReviews.length} reviews (${storeSummary}) | Avg: ${avgRating}/5 ===`;
  reviewText += `\nDATA COVERAGE: ${appReviews.length} most recent reviews from ${storesCoveredLabel}, dated ${oldestDate} to ${newestDate}\n`;

  for (const r of appReviews) {
    if (!r.review || r.review.trim().length < 5) continue;
    reviewText += `[${r.rating}★][${r.store}] ${r.title ? r.title + ': ' : ''}${r.review}\n`;
  }
}

const appMetaJson = JSON.stringify(appMeta);

const prompt = `You are a product analyst. Analyze the following app store 
reviews and generate a complete, self-contained HTML email 
report.

APP METADATA (use for logos and display):
${appMetaJson}

REVIEWS DATA:
${reviewText}

Generate a complete HTML document with inline CSS 
(no external stylesheets). The report should:

DESIGN:
- Clean white background, professional font (Arial/Helvetica)
- A header bar with dark background (#1a1a2e) showing 
  "App Reviews Report for [comma separated list of apps]" 
  and the date
- For each app: show the app logo (60x60px rounded), 
  app name as heading
- Color-coded sentiment badge: green for positive majority, 
  red for negative majority, orange for mixed
- Section cards with light grey background (#f8f9fa), 
  subtle border, padding
- Complaint items in light red pills, praise items in 
  light green pills
- Critical issues highlighted in a red-bordered alert box
- Clean bullet points for recommendations
- Footer with generation timestamp

ANALYSIS APPROACH:
- STRICT DATA GROUNDING: Generate ALL insights, complaints, 
  praises, themes, and recommendations exclusively from the 
  review text provided. Do not infer, assume, or extrapolate 
  from general knowledge about the app or industry. If a 
  complaint is not explicitly stated in at least 2 separate 
  reviews, do not include it. Every insight must be 
  traceable to specific reviews in the data provided.
- Synthesize insights holistically across both stores where 
  data exists — do not repeat the same point twice
- For general issues, report as a unified insight without 
  mentioning the store
- EXCEPTION: for technical issues (app crashes, login 
  failures, payment bugs, UI glitches, performance, 
  OS-specific errors) — always mention which store the 
  issue was reported from [App Store] / [Play Store] / 
  [Both Stores]
- Frequency estimates should reflect combined review count

SECTIONS FOR EACH APP:

1. App header with logo, name, sentiment badge (DO NOT show 
   star rating or numeric rating), and a metadata chip 
   showing e.g. "Based on 200 most recent reviews · 
   App Store + Play Store · Apr 15–17 2026"

2. Overall Sentiment Analysis:

   Classification rules:
   - Classify each review by TEXT CONTENT, not star rating
   - Positive: text expresses satisfaction, praise, or 
     recommendation regardless of star rating
   - Negative: text expresses frustration, complaint, 
     dissatisfaction, or warning to others
   - Neutral: factual observations with no clear emotional 
     valence
   - Mixed: significant praise AND significant complaint 
     in same review — count as 0.5 positive + 0.5 negative
   - Single generic words ("good", "nice", "ok") without 
     context — exclude from sentiment calculation entirely
   - Where star rating contradicts text sentiment, 
     trust the text

   Output:
   - % positive / % negative / % neutral (must sum to 100%)
   - Note if star rating distribution significantly differs 
     from text sentiment — this gap is itself a product 
     signal worth surfacing
   - One-line summary of the dominant sentiment theme

3. Top Complaints — top 3-5 recurring issues as red pills, 
   each with approximate % of reviews mentioning it. 
   Unified across stores unless platform-specific. Only 
   include if mentioned in at least 2 separate reviews.

4. Top Praises — top 2-3 things users explicitly praise 
   as green pills, each with approximate frequency. Only 
   include if genuinely present in review text — do not 
   invent praises if the data does not support them.

5. Technical Issues — only include if genuine technical 
   complaints exist (crashes, bugs, payment failures, 
   login issues, performance). Each issue must specify 
   [App Store] / [Play Store] / [Both Stores]. Red-bordered 
   alert box. Skip entirely if no technical issues exist.

6. Key Themes — 3-5 high-level conceptual themes that 
   characterise the user experience, distinct from specific 
   complaints. Should be broader patterns e.g. "Trust 
   erosion", "Accountability gap", "Expectation mismatch" 
   — not repetitions of complaints listed above.

7. Actionable Recommendations — 2-3 specific, prioritised 
   recommendations. Each must:
   - Be directly traceable to a complaint in the data above
   - State WHAT to fix, not just THAT it needs fixing
   - Reference the approximate % of reviews that support it
   e.g. "Introduce proactive delay notifications — 68% of 
   negative reviews cite unexpected delays with no 
   communication"

8. Store Experience Comparison — ONLY if reviews exist 
   from BOTH stores. Compare:
   - Sentiment distribution across platforms
   - Whether top complaints are the same or different
   - Complaints exclusive to one platform
   - Language intensity differences between platforms
   If experience is identical, state clearly: "No 
   meaningful difference between iOS and Android user 
   experience based on available reviews"

IMPORTANT:
- Return ONLY the complete HTML document starting with 
  <!DOCTYPE html>
- All CSS must be inline or in a <style> tag in <head>
- No markdown, no explanation, just the HTML
- Make it look like a professional product analytics report
- Quote actual user language where impactful — specific 
  phrases from reviews are more credible than paraphrasing
- If fewer than 10 substantive reviews are available from 
  a given store, note "Insufficient data from [store] 
  for reliable analysis" rather than generating insights 
  from too small a sample`;



// NEW — return plain object
return [{
  json: {
    body: {
      contents: [
        {
          role: "user",
          parts: [{ text: prompt }]
        }
      ],
      generationConfig: {
        temperature: 0.3,
        maxOutputTokens: 65536
      }
    },
    reportMetadata,
    totalReviews: data.totalReviews,
    fetchedAt: data.fetchedAt
  }
}];

const response = $input.first().json;

let report = response?.candidates?.[0]?.content?.parts?.[0]?.text || '';

report = report.replace(/^```html\n?/i, '').replace(/```$/i, '').trim();

return [{
  json: {
    report,
    reportBase64: Buffer.from(report, 'utf8').toString('base64'),
    generatedAt: new Date().toISOString()
  }
}];

